<section class="py-3"><div class="container"><div class="d-flex justify-content-between align-items-center mb-3"><h1 class="h4 fw-bold mb-0 text-capitalize">Manage <?= e(str_replace('_',' ',$entity)) ?></h1><div><a class="btn btn-primary" href="<?= e(base_url('admin/create/' . $entity)) ?>">Add New</a> <a class="btn btn-outline-secondary" href="<?= e(base_url('admin')) ?>">Dashboard</a></div></div><?php if ($msg=flash('success')): ?><div class="alert alert-success"><?= e($msg) ?></div><?php endif; ?><div class="table-responsive soft-card p-3"><table class="table table-sm align-middle"><thead><tr><?php if(!empty($rows)): foreach(array_keys($rows[0]) as $h): ?><th><?= e($h) ?></th><?php endforeach; endif; ?><th>Visibility</th><th>Actions</th></tr></thead><tbody><?php foreach($rows as $row): ?><tr><?php foreach($row as $v): ?><td><?= e((string)$v) ?></td><?php endforeach; ?><td><?php $hiddenIds = $hiddenIds ?? []; $isVisible = !in_array((int)$row['id'], $hiddenIds, true); ?><a class="btn btn-sm <?= $isVisible ? 'btn-outline-success' : 'btn-outline-warning' ?>" href="<?= e(base_url('admin/toggle/' . $entity . '/' . $row['id'])) ?>" title="<?= $isVisible ? 'Visible' : 'Hidden' ?>"><?= $isVisible ? '<i class="bi bi-eye"></i>' : '<i class="bi bi-eye-slash"></i>' ?></a></td><td class="d-flex gap-1"><a class="btn btn-sm btn-outline-primary" href="<?= e(base_url('admin/edit/' . $entity . '/' . $row['id'])) ?>">Edit</a><a class="btn btn-sm btn-outline-danger" href="<?= e(base_url('admin/delete/' . $entity . '/' . $row['id'])) ?>" onclick="return confirm('Delete item?')">Delete</a></td></tr><?php endforeach; ?></tbody></table></div></div></section>
